(335,'Henno Täht lisas õpilasele Sander Tuisk tagasisideks: \'Ei näinud cite, dialog, div, figcaption, figure, h2, hr, kbd, link, main, ol, picture, samp, small, span, sub, sup, svg, template, tfoot, video elemente.\'',10,1,'2024-10-24 16:48:35',1),
(336,'Henno Täht muutis õpilase Sander Tuisk hinnet:  -> MA',10,1,'2024-10-24 16:48:35',1),
(337,'Henno Täht märkis õpilasele Olga Morgunova kriteeriumi \'Repo main harus ei ole üleliigset koodi, näiteks koopiafaile koodist.\' mittetehtuks.',1,1,'2024-10-24 16:53:47',1),
(338,'Henno Täht märkis õpilasele Olga Morgunova kriteeriumi \'Main harus on fail README.md, milles on projekti pealkiri, õpetus, kuidas projekti kasutada ja deploy link, millega saab projekti koodi käima lasta. Näiteks GitHub Pages, Replit.com vms\' mittetehtuks.',1,1,'2024-10-24 16:53:47',1),
(339,'Henno Täht märkis õpilasele Olga Morgunova kriteeriumi \'Lahenduses on kasutatud kõiki eelnevalt käsitletud programeerimiskontseptsioone (muutujad, funktsioonid, tingimused tsüklid).\' tehtuks.',1,1,'2024-10-24 16:53:47',1),
(340,'Henno Täht muutis õpilase Olga Morgunova tagasisidet: \'README failis on kasutamisõpetuses viga.\' -> \'Projektis on liigne alamkaust. README-s pole linki, kuhu vajutada, et saaks koodi käivitada (kui sul õnnestub telefonis programm käima saada, kasutades Replit vms keskkonda, siis pane vastav juhend README-sse, kuidas seda teha, soovitatavalt Replit vms lingina)\'',1,1,'2024-10-24 16:53:47',1),
(341,'Henno Täht märkis õpilasele Brigita Kasemets kriteeriumi \'Teemad tabelis on Dokumenteerija tulbas sinu nimi ühe projekti repo taga (mis ei ole sinu enda oma)\' tehtuks.',2,1,'2024-10-24 20:15:01',1),
(342,'Henno Täht märkis õpilasele Brigita Kasemets kriteeriumi \'Oled forkinud selle inimese projekti enda Githubi konto alla\' tehtuks.',2,1,'2024-10-24 20:15:01',1),
