(942,'Henno Täht lisas õpilase Lembit Lindau lahenduse tagasisideks: \'Ei lähe käima:\n```\n$ git clone git@github.com:lembitlindau/Bussiajad.git\nCloning into \'Bussiajad\'...\nEnter passphrase for key \'/Users/henno/.ssh/id_rsa\':\nremote: Enumerating objects: 66, done.\nremote: Counting objects: 100% (66/66), done.\nremote: Compressing objects: 100% (40/40), done.\nremote: Total 66 (delta 19), reused 57 (delta 13), pack-reused 0 (from 0)\nReceiving objects: 100% (66/66), 33.59 KiB | 386.00 KiB/s, done.\nResolving deltas: 100% (19/19), done.\n\n$ cd Bussiajad/\n\n$ git checkout 1-Names-of-the-bus-stops\nbranch \'1-Names-of-the-bus-stops\' set up to track \'origin/1-Names-of-the-bus-stops\'.\nSwitched to a new branch \'1-Names-of-the-bus-stops\'\n\n$ mysql -u root -proot -e \"CREATE DATABASE Bussiajad\"\n\n$ mysql -u root -proot Bussiajad < dump.sql\n\n$ mysql -u root -proot Bussiajad < trigerid.sql\n--------------\nCREATE TRIGGER before_departure_insert\n    BEFORE INSERT ON departures\n    FOR EACH ROW\nBEGIN\n\n    IF EXISTS (\n        SELECT 1\n        FROM departures\n        WHERE station_id = NEW.station_id\n          AND departure_time = NEW.departure_time\n          AND sequence_number = NEW.sequence_number\n    ) THEN\n        SIGNAL SQLSTATE \'45000\'\n            SET MESSAGE_TEXT = \'Duplicate departure time for the same station is not allowed\';\n    END IF;\nEND\n--------------\n\nERROR 1054 (42S22) at line 24: Unknown column \'sequence_number\' in \'NEW\'\n\n$\n```\n\'',18,1,'2024-12-22 13:15:01',1),
