(9,11,3,'A','https://github.com/lembitlindau/Bussiajad','[{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"README k\\u00e4sib p\\u00e4rast `npm install` k\\u00e4sku k\\u00e4ivitada `node init-db.js`, kuid sellist faili pole olemas.\",\"createdAt\":\"2024-12-05 13:45:22\"},{\"name\":\"Lembit Lindau\",\"comment\":\"README peaks n\\u00fc\\u00fcd korras olema\",\"createdAt\":\"2024-12-05 15:07:31\"},{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"README tsiteerib markdownis readmed.\",\"createdAt\":\"2024-12-06 17:55:14\"},{\"name\":\"Lembit Lindau\",\"comment\":\"README tsiteerib markdownis readmed - Kustutatud\",\"createdAt\":\"2024-12-07 10:33:28\"},{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"Ei \\u00f5nnestu READMEd j\\u00e4rgida: https:\\/\\/photos.app.goo.gl\\/T6pL3T9ZGi5muKeLA\",\"createdAt\":\"2024-12-07 19:57:57\"},{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"Ekraanipildil oli minu poolt v\\u00e4ike viga, kuid see ei muutnud l\\u00f5pptulemust: https:\\/\\/photos.app.goo.gl\\/egAM56ueRMgmtR7t6\",\"createdAt\":\"2024-12-07 20:00:34\"},{\"name\":\"Lembit Lindau\",\"comment\":\"Tegin kehtestuse ning kohe m\\u00e4rkasin ka oma viga. Ma ei teinud k\\u00f5igi failide ees linnukest\",\"createdAt\":\"2024-12-15 16:56:11\"},{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"M\\u00e4rkasin, et vahetasid projekti selles \\u00fclesandes. Siiski, esimene kasutajalugu bussiaegade projektis on sul \\\"list bus stops\\\", kuid kui koodi vaadata, siis n\\u00e4en seal ka muud funktsionaalsust, mida seal veel olla ei tohiks: https:\\/\\/github.com\\/lembitlindau\\/Bussiajad\\/commit\\/62d42b681a2192cdcbb568cb4bb7e3faaf488846#diff-0eb547304658805aad788d320f10bf1f292797b5e6d745a3bf617584da017051R16\",\"createdAt\":\"2024-12-17 01:21:14\"}]','1970-01-01 00:00:00',NULL,NULL),
