(10,40,3,'A','https://github.com/Sigmartreumann/issue-tracker','[{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"Sinu HTML faili on vaja lisada veel j\\u00e4rgnevad elemendid: !--, a, abbr, address, article, audio, blockquote, br, canvas, caption, cite, code, col, colgroup, del, details, dialog, div, figcaption, figure, footer, h3, hr, iframe, img, ins, kbd, li, link, main, mark, nav, ol, optgroup, picture, pre, samp, script, small, source, span, strong, sub, sup, svg, template, tfoot, ul, video\",\"createdAt\":\"2024-11-27 22:53:41\"},{\"name\":\"Sigmar Treumann\",\"comment\":\"Tegin t\\u00e4iendused n\\u00fc\\u00fcd peaks olema k\\u00f5ik vajalik.\",\"createdAt\":\"2024-12-05 07:44:13\"},{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"Missing elements: a, abbr, address, article, audio, blockquote, br, canvas, caption, cite, code, col, colgroup, del, details, dialog, fieldset, figcaption, figure, footer, form, h1, header, hr, iframe, img, ins, kbd, legend, li, link, main, mark, nav, ol, optgroup, p, picture, pre, samp, section, small, source, span, strong, sub, sup, svg, template, tfoot, ul, video\",\"createdAt\":\"2024-12-05 12:25:59\"},{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"Esita see \\u00fclesanne eraldi repoga, et see ei solgiks sinu hobiprojekti kehtestusi.\",\"createdAt\":\"2024-12-05 13:52:43\"}]','1970-01-01 00:00:00',NULL,NULL),
