(14,40,3,'A','https://github.com/Sigmartreumann/Hobiprojekt/blob/main/dump.sql','[{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"Edaspidi \\u00e4ra tee eestikeelseid v\\u00e4ljanimesid, sest see tekitab IDEs rohelisi lainelisi joonekesi nimede alla ja speller ei t\\u00f6\\u00f6ta. Samuti v\\u00f5ib t\\u00e4pit\\u00e4htedega tabeli ja v\\u00e4ljade nimedes m\\u00f5nede andmebaaside puhul tekkida probleeme.\",\"createdAt\":\"2024-11-20 18:46:11\"}]','1970-01-01 00:00:00',NULL,NULL),
