(17,11,3,'A','https://github.com/lembitlindau/Bussiajad/blob/1-Names-of-the-bus-stops/query.sql','[{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"Uuendada README\",\"createdAt\":\"2024-12-05 11:32:03\"},{\"name\":\"Lembit Lindau\",\"comment\":\"README uuendatud\",\"createdAt\":\"2024-12-05 15:24:51\"},{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"Liinide arve p\\u00e4ringus on valitud ka liini id. See pole loogiline (proovi ise v\\u00e4lja selgitada, miks)\",\"createdAt\":\"2024-12-05 18:38:02\"},{\"name\":\"Lembit Lindau\",\"comment\":\"Nii oleks \\u00f5ige:\\n\\nselect count(distinct line_id) as line_count\\nfrom routes;\",\"createdAt\":\"2024-12-07 21:26:15\"}]','1970-01-01 00:00:00',NULL,NULL),
