(17,24,3,'A','https://github.com/EeroVallistu/dropshipwebpage/blob/main/inquiries.sql','[{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"README-s puudub juhend, kuidas backend serverit k\\u00e4ima panna ja kuidas andmebaasi importida ja puuduvad n\\u00e4idisandmed, mille peal p\\u00e4ringuid k\\u00e4itada.\",\"createdAt\":\"2024-12-05 11:22:13\"},{\"name\":\"Henno T\\u00e4ht\",\"comment\":\"README-s muuta andmebaasi seadistamise juhendit nii, et kasutaja peaks v\\u00f5imalikult v\\u00e4he seda ise muutma ning et kui j\\u00e4rjest k\\u00e4sud k\\u00e4ima panna, siis nad t\\u00f6\\u00f6taks\",\"createdAt\":\"2024-12-05 12:36:41\"}]','1970-01-01 00:00:00',NULL,NULL),
